from pathlib import Path

# :name: map_html_element
# :description: Mappe un tag HTML vers un composant standard défini dans le fichier mapping_rules.json
# :inputs: tag_name (str), attributes (dict)
# :output: dict contenant la correspondance trouvée ou une instruction IA

MAPPING_FILE = Path("/Users/nathalie/Dropbox/PROJETS/LANOSTRAI/_LANOSTRAI/objects/roles/render/resources/json/mapping_rules.json")


def load_mapping_rules():
    with open(MAPPING_FILE, "r") as f:
        return json.load(f)


def map_html_element(tag_name: str, attributes: dict = None) -> dict:
    rules = load_mapping_rules()
    for rule in rules:
        if rule.get("match") == tag_name:
            result = {"component": rule["map_to"], "category": rule.get("category")}
            if "level" in rule:
                result["level"] = rule["level"]
            if rule.get("map_to") == "ai_resolve":
                result["handler"] = rule.get("handler", "resolve_unknown_tag_AI")
                result["original_tag"] = tag_name
                result["attributes"] = attributes or {}
            return result

    # Si non trouvé explicitement, fallback IA
    return {
        "component": "ai_resolve",
        "handler": "resolve_unknown_tag_AI",
        "original_tag": tag_name,
        "attributes": attributes or {}
    }"
}

