import json
from bs4 import BeautifulSoup

# :name: scrape_build_dom_hierarchy
# :description: Construit la hiérarchie DOM d'une page scrappée et la sauvegarde en JSON, avec injection de la balise DOCTYPE
# :inputs: chemin HTML en entrée, chemin de sortie JSON
# :outputs: JSON hiérarchique contenant tous les éléments HTML depuis DOCTYPE

def convert_node(node):
    if isinstance(node, str):
        return {"tag": "text", "text": node.strip()}

    tag = node.name
    if tag is None:
        return None

    attributes = dict(node.attrs)
    children = [convert_node(child) for child in node.children if child and convert_node(child)]

    return {
        "tag": tag,
        "attributes": attributes,
        "children": children
    }

def scrape_build_dom_hierarchy(html_path, output_path):
    with open(html_path, "r", encoding="utf-8") as f:
        soup = BeautifulSoup(f, "html.parser")

    html_root = soup.find("html")
    if not html_root:
        raise ValueError("Balise <html> non trouvée dans le fichier source.")

    dom_tree = convert_node(html_root)

    # Injecte le noeud DOCTYPE en tête
    doctype_node = {
        "tag": "!DOCTYPE",
        "attributes": {"html": ""},
        "children": []
    }

    final_tree = [doctype_node, dom_tree]

    with open(output_path, "w", encoding="utf-8") as f:
        json.dump(final_tree, f, indent=2, ensure_ascii=False)

    print(f"✅ Fichier DOM JSON généré : {output_path}")"
    }
