import os
import json

# Dictionnaire de correspondance des balises et attributs
from objects.roles.render.resources.mapping.reference_mapping import reference_mapping

def recursive_map(element):
    tag = element.get("tag")
    mapped_tag = reference_mapping.get(tag, {}).get("tag", tag)

    mapped_element = {
        "tag": mapped_tag,
        "attrs": {},
        "children": []
    }

    # Attributs
    for attr, val in element.get("attrs", {}).items():
        if attr in reference_mapping.get(tag, {}).get("attrs", {}):
            mapped_attr = reference_mapping[tag]["attrs"][attr]
        else:
            mapped_attr = attr  # fallback identique
        mapped_element["attrs"][mapped_attr] = val

    # Fallback IA si tag inconnu (optionnel - ici simplifié)
    if tag not in reference_mapping:
        mapped_element["meta"] = {"status": "unmapped"}

    # Children
    for child in element.get("children", []):
        mapped_element["children"].append(recursive_map(child))

    return mapped_element

def map_scraped_dom_json(input_path):
    with open(input_path, "r", encoding="utf-8") as f:
        data = json.load(f)

    mapped_data = recursive_map(data)
    mapped_data["meta"] = {"status": "pending"}

    output_path = input_path.replace("_dom_converted.json", "_mapped.json")
    with open(output_path, "w", encoding="utf-8") as f:
        json.dump(mapped_data, f, indent=2)

