import json
import os
import builtins
from pathlib import Path

# Chargement du fichier de mapping depuis les builtins
try:
    MAPPING_FILE = builtins.MAPPING_FILE
except AttributeError:
    print("❌ Erreur : MAPPING_FILE n’est pas défini dans les builtins.")
    exit()

def load_mapping_rules(mapping_path):
    try:
        with open(mapping_path, 'r') as f:
            raw_rules = json.load(f)
        print(f"📖 Fichier de mapping chargé : {mapping_path}")
    except Exception as e:
        print(f"❌ Erreur de chargement du fichier de mapping : {e}")
        return {}

    # Conversion liste -> dictionnaire
    if isinstance(raw_rules, list):
        return {
            item["tag"]: item["mapped"]
            for item in raw_rules
            if "tag" in item and "mapped" in item
        }
    elif isinstance(raw_rules, dict):
        return raw_rules
    else:
        print("❌ Format de mapping non reconnu.")
        return {}

def map_element(element, mapping_rules):
    tag = element.get("tag", "")
    mapped_tag = mapping_rules.get(tag, tag)
    element["tag"] = mapped_tag

    if "children" in element and isinstance(element["children"], list):
        element["children"] = [map_element(child, mapping_rules) for child in element["children"]]
    return element

def map_multiple_scraped_jsons(dict_of_paths, mapping_rules):
    for input_path, output_path in dict_of_paths.items():
        try:
            print(f"🔍 Traitement de : {input_path}")
            with open(input_path, 'r') as f:
                original_data = json.load(f)

            # Si la racine est une liste, mapper chaque élément
            if isinstance(original_data, list):
                mapped_data = [map_element(el, mapping_rules) for el in original_data]
            else:
                mapped_data = map_element(original_data, mapping_rules)

            with open(output_path, 'w') as f:
                json.dump(mapped_data, f, indent=2)

            print(f"✅ Fichier mappé sauvegardé : {output_path}")
        except Exception as e:
