import json
from starlette.responses import HTMLResponse


def render_node(node):
    tag = node.get("tag", "")
    attributes = node.get("attributes", {})
    children = node.get("children", [])
    text = node.get("text", "")

    attr_str = " ".join(f'{key}="{value}"' for key, value in attributes.items())
    attr_str = f" {attr_str}" if attr_str else ""

    children_html = "".join(
        render_node(child) if isinstance(child, dict) else str(child)
        for child in children
    )

    if tag.lower() in ["meta", "link", "br", "hr", "img", "input"]:
        return f"<{tag}{attr_str}/>
"

    return f"<{tag}{attr_str}>{text}{children_html}</{tag}>\n"


def render_template_from_json(json_path):
    try:
        with open(json_path, "r") as f:
            data = json.load(f)
    except Exception as e:
        return HTMLResponse(content=f"❌ Erreur lors du chargement : {e}", status_code=500)

    if isinstance(data, list):
        html_content = "".join(render_node(node) for node in data)
    else:
        html_content = render_node(data)

    return HTMLResponse(content=f"<!DOCTYPE html>\n{html_content}", status_code=200)"}

