```python
# :name: scrape_build_dom_hierarchy
# :description: Extrait la hiérarchie DOM d'un site avec les classes, styles et attributs.
# :input: url (str)
# :output: dict (hiérarchie DOM structurée)

import requests
from bs4 import BeautifulSoup, NavigableString, Tag

def scrape_build_dom_hierarchy(url):
    print(f"🌐 Récupération du HTML depuis : {url}")
    response = requests.get(url)
    soup = BeautifulSoup(response.text, 'html.parser')

    def extract_attributes(element):
        attrs = dict(element.attrs)
        styles = {}
        if 'style' in attrs:
            for item in attrs['style'].split(';'):
                if ':' in item:
                    key, value = item.split(':', 1)
                    styles[key.strip()] = value.strip()
            attrs['style'] = styles
        return attrs

    def parse_node(node):
        if isinstance(node, NavigableString):
            return node.strip() if node.strip() else None

        if not isinstance(node, Tag):
            return None

        children = [parse_node(child) for child in node.children]
        children = [child for child in children if child]

        return {
            'tag': node.name,
            'attributes': extract_attributes(node),
            'children': children
        }

    print("🧱 Construction de la hiérarchie DOM...")
    dom_structure = parse_node(soup.body or soup)

    print("✅ Hiérarchie DOM construite.")
    return dom_structure
```

