# :name: superRenderer
# :description: Génère un HTML à partir d'une hiérarchie DOM JSON.
# :input: json_data (dict)
# :output: str (HTML)

def render_template(json_data):
    def render_attributes(attributes):
        if not attributes:
            return ""
        rendered = []
        for key, value in attributes.items():
            if key == "style" and isinstance(value, dict):
                style_str = "; ".join(f"{k}: {v}" for k, v in value.items())
                rendered.append(f'style="{style_str}"')
            elif isinstance(value, list):
                rendered.append(f'{key}="{" ".join(value)}"')
            else:
                rendered.append(f'{key}="{value}"')
        return " " + " ".join(rendered)

    def recurse(node):
        if isinstance(node, list):
            return "".join(recurse(child) for child in node)

        if isinstance(node, str):
            return node

        tag = node.get("tag", "div")
        attributes = render_attributes(node.get("attributes", {}))
        children = node.get("children", [])
        inner_html = "".join(recurse(child) for child in children)
        return f"<{tag}{attributes}>{inner_html}</{tag}>"

    return recurse(json_data)
```

