```python
# :name: scrape_build_dom_hierarchy
# :description: Scrape une page HTML et construit une hiérarchie DOM mappée au format JSON enrichi
# :input: url (str)
# :output: dom_json (dict)

from bs4 import BeautifulSoup, Comment
import requests
import json
from urllib.parse import urljoin

def scrape_build_dom_hierarchy(url):
    response = requests.get(url)
    soup = BeautifulSoup(response.text, 'html.parser')
    base_url = response.url

    def extract_attributes(tag):
        attributes = {}
        for attr, value in tag.attrs.items():
            if isinstance(value, list):
                value = " ".join(value)
            attributes[attr] = value
        return attributes

    def node_to_dict(node, source='body'):
        if isinstance(node, str):
            return {"tag": "text", "raw_content": node.strip(), "source": source}

        if isinstance(node, Comment):
            return None  # Ignore les commentaires HTML

        item = {
            "tag": node.name,
            "attrs": extract_attributes(node),
            "source": source,
        }

        # Récupère le style inline si présent
        if 'style' in node.attrs:
            item["inline_style"] = node.attrs["style"]

        # Contenu texte brut si pertinent
        text_content = node.get_text(strip=True)
        if text_content:
            item["raw_content"] = text_content

        # Récursivité sur les enfants
        children = [node_to_dict(child, source=source) for child in node.children]
        children = [child for child in children if child]
        if children:
            item["children"] = children

        return item

    def extract_head_elements(soup):
        head = soup.head
        head_elements = []
        if head:
            for tag in head.find_all(recursive=False):
                element = node_to_dict(tag, source='head')
                if element:
                    head_elements.append(element)
        return head_elements

    def extract_body_elements(soup):
        body = soup.body
        body_elements = []
        if body:
            for tag in body.find_all(recursive=False):
                element = node_to_dict(tag, source='body')
                if element:
                    body_elements.append(element)
        return body_elements

    dom_json = {
        "source_url": base_url,
        "head": extract_head_elements(soup),
        "body": extract_body_elements(soup)
    }

    return dom_json

