## ✅ Nouveau fichier : `generate_relative_color_variables.py`

```python
# :name: generate_relative_color_variables
# :description: Génère des variables SCSS relatives à la couleur principale, exprimées en décalage HSL
# :inputs: colors (list[str])
# :outputs: dictionnaire avec les noms ($primary, $secondary...) et leurs différences relatives (H, S, L)

import colorsys
from collections import OrderedDict

def hex_to_rgb(hex_color):
    hex_color = hex_color.lstrip("#")
    return tuple(int(hex_color[i:i+2], 16)/255.0 for i in (0, 2, 4))

def rgb_to_hsl(r, g, b):
    h, l, s = colorsys.rgb_to_hls(r, g, b)  # output is HLS → reordered to HSL
    return h, s, l

def generate_relative_variables(colors):
    if not colors:
        return {}

    hsl_data = OrderedDict()
    for color in colors:
        try:
            r, g, b = hex_to_rgb(color)
            h, s, l = rgb_to_hsl(r, g, b)
            hsl_data[color] = {"hue": h, "saturation": s, "lightness": l}
        except:
            continue

    # Choix de la couleur principale : la plus saturée × lumineuse
    dominant = max(hsl_data.items(), key=lambda x: x[1]['saturation'] * x[1]['lightness'])
    base_hex = dominant[0]
    base_hsl = dominant[1]

    result = {
        "$primary": {
            "hex": base_hex,
            "hue": round(base_hsl["hue"], 4),
            "saturation": round(base_hsl["saturation"], 4),
            "lightness": round(base_hsl["lightness"], 4)
        }
    }

    count = 1
    for hex_color, hsl in hsl_data.items():
        if hex_color == base_hex:
            continue
        name = f"$color{count}"
        result[name] = {
            "hex": hex_color,
            "hue_offset": round(hsl["hue"] - base_hsl["hue"], 4),
            "saturation_ratio": round(hsl["saturation"] / base_hsl["saturation"], 4) if base_hsl["saturation"] else 0,
            "lightness_ratio": round(hsl["lightness"] / base_hsl["lightness"], 4) if base_hsl["lightness"] else 0
        }
        count += 1

    return result

if __name__ == "__main__":
    palette = ['#ffffff', '#333333', '#b49982', '#8a6743']
    variables = generate_relative_variables(palette)
    import json
    print(json.dumps(variables, indent=2))
```

